   188→	if pod.Spec.SecurityContext != nil {
   189→		sc := pod.Spec.SecurityContext
   190→		if sc.RunAsUser != nil && runtime.GOOS != "windows" {
   191→			lc.SecurityContext.RunAsUser = &runtimeapi.Int64Value{Value: int64(*sc.RunAsUser)}
   192→		}
   193→		if sc.RunAsGroup != nil && runtime.GOOS != "windows" {
   194→			lc.SecurityContext.RunAsGroup = &runtimeapi.Int64Value{Value: int64(*sc.RunAsGroup)}
   195→		}
   196→		namespaceOptions, err := runtimeutil.NamespacesForPod(pod, m.runtimeHelper, m.runtimeClassManager)
   197→		if err != nil {
   198→			return nil, err
   199→		}
   200→		lc.SecurityContext.NamespaceOptions = namespaceOptions
   201→
   202→		if sc.FSGroup != nil && runtime.GOOS != "windows" {
   203→			lc.SecurityContext.SupplementalGroups = append(lc.SecurityContext.SupplementalGroups, int64(*sc.FSGroup))
   204→		}
   205→		if groups := m.runtimeHelper.GetExtraSupplementalGroupsForPod(pod); len(groups) > 0 {
   206→			lc.SecurityContext.SupplementalGroups = append(lc.SecurityContext.SupplementalGroups, groups...)
   207→		}
   208→		if sc.SupplementalGroups != nil {
   209→			for _, sg := range sc.SupplementalGroups {
   210→				lc.SecurityContext.SupplementalGroups = append(lc.SecurityContext.SupplementalGroups, int64(sg))
   211→			}
   212→		}
   213→		if sc.SupplementalGroupsPolicy != nil {
   214→			policyValue, ok := runtimeapi.SupplementalGroupsPolicy_value[string(*sc.SupplementalGroupsPolicy)]
   215→			if !ok {
   216→				return nil, fmt.Errorf("unsupported supplementalGroupsPolicy: %s", string(*sc.SupplementalGroupsPolicy))
   217→			}
   218→			lc.SecurityContext.SupplementalGroupsPolicy = runtimeapi.SupplementalGroupsPolicy(policyValue)
   219→		}
   220→
   221→		if sc.SELinuxOptions != nil && runtime.GOOS != "windows" {
   222→			lc.SecurityContext.SelinuxOptions = &runtimeapi.SELinuxOption{
   223→				User:  sc.SELinuxOptions.User,
   224→				Role:  sc.SELinuxOptions.Role,
   225→				Type:  sc.SELinuxOptions.Type,
   226→				Level: sc.SELinuxOptions.Level,
   227→			}
   228→		}
   229→	}
   230→
   231→	return lc, nil
   232→}
   233→
   234→// generatePodSandboxWindowsConfig generates WindowsPodSandboxConfig from v1.Pod.
   235→// On Windows this will get called in addition to LinuxPodSandboxConfig because not all relevant fields have been added to
   236→// WindowsPodSandboxConfig at this time.
   237→func (m *kubeGenericRuntimeManager) generatePodSandboxWindowsConfig(pod *v1.Pod) (*runtimeapi.WindowsPodSandboxConfig, error) {
   238→	wc := &runtimeapi.WindowsPodSandboxConfig{
   239→		SecurityContext: &runtimeapi.WindowsSandboxSecurityContext{},
   240→	}
   241→
   242→	if utilfeature.DefaultFeatureGate.Enabled(features.WindowsHostNetwork) {
   243→		wc.SecurityContext.NamespaceOptions = &runtimeapi.WindowsNamespaceOption{}
   244→		if kubecontainer.IsHostNetworkPod(pod) {
   245→			wc.SecurityContext.NamespaceOptions.Network = runtimeapi.NamespaceMode_NODE
   246→		} else {
   247→			wc.SecurityContext.NamespaceOptions.Network = runtimeapi.NamespaceMode_POD
   248→		}
   249→	}
   250→
   251→	// If all of the containers in a pod are HostProcess containers, set the pod's HostProcess field
   252→	// explicitly because the container runtime requires this information at sandbox creation time.
   253→	if kubecontainer.HasWindowsHostProcessContainer(pod) {
   254→		// At present Windows all containers in a Windows pod must be HostProcess containers
   255→		// and HostNetwork is required to be set.
   256→		if !kubecontainer.AllContainersAreWindowsHostProcess(pod) {
   257→			return nil, fmt.Errorf("pod must not contain both HostProcess and non-HostProcess containers")
   258→		}
   259→
   260→		if !kubecontainer.IsHostNetworkPod(pod) {
   261→			return nil, fmt.Errorf("hostNetwork is required if Pod contains HostProcess containers")
   262→		}
   263→
   264→		wc.SecurityContext.HostProcess = true
   265→	}
   266→
   267→	sc := pod.Spec.SecurityContext
   268→	if sc == nil || sc.WindowsOptions == nil {
   269→		return wc, nil
   270→	}
   271→
   272→	wo := sc.WindowsOptions
   273→	if wo.GMSACredentialSpec != nil {
   274→		wc.SecurityContext.CredentialSpec = *wo.GMSACredentialSpec
   275→	}
   276→
   277→	if wo.RunAsUserName != nil {
   278→		wc.SecurityContext.RunAsUsername = *wo.RunAsUserName
   279→	}
   280→
   281→	if kubecontainer.HasWindowsHostProcessContainer(pod) {
   282→
   283→		if wo.HostProcess != nil && !*wo.HostProcess {
   284→			return nil, fmt.Errorf("pod must not contain any HostProcess containers if Pod's WindowsOptions.HostProcess is set to false")
   285→		}
   286→	}
   287→
   288→	return wc, nil
   289→}
   290→
   291→// getKubeletSandboxes lists all (or just the running) sandboxes managed by kubelet.
   292→func (m *kubeGenericRuntimeManager) getKubeletSandboxes(ctx context.Context, all bool) ([]*runtimeapi.PodSandbox, error) {
   293→	var filter *runtimeapi.PodSandboxFilter
   294→	if !all {
   295→		readyState := runtimeapi.PodSandboxState_SANDBOX_READY
   296→		filter = &runtimeapi.PodSandboxFilter{
   297→			State: &runtimeapi.PodSandboxStateValue{
   298→				State: readyState,
   299→			},
   300→		}
   301→	}
   302→
   303→	resp, err := m.runtimeService.ListPodSandbox(ctx, filter)
   304→	if err != nil {
   305→		klog.ErrorS(err, "Failed to list pod sandboxes")
   306→		return nil, err
   307→	}
   308→
   309→	return resp, nil
   310→}
   311→
   312→// determinePodSandboxIP determines the IP addresses of the given pod sandbox.
   313→func (m *kubeGenericRuntimeManager) determinePodSandboxIPs(podNamespace, podName string, podSandbox *runtimeapi.PodSandboxStatus) []string {
   314→	podIPs := make([]string, 0)
   315→	if podSandbox.Network == nil {
   316→		klog.InfoS("Pod Sandbox status doesn't have network information, cannot report IPs", "pod", klog.KRef(podNamespace, podName))
   317→		return podIPs
   318→	}
   319→
   320→	// ip could be an empty string if runtime is not responsible for the
   321→	// IP (e.g., host networking).
   322→
   323→	// pick primary IP
   324→	if len(podSandbox.Network.Ip) != 0 {
   325→		if netutils.ParseIPSloppy(podSandbox.Network.Ip) == nil {
   326→			klog.InfoS("Pod Sandbox reported an unparseable primary IP", "pod", klog.KRef(podNamespace, podName), "IP", podSandbox.Network.Ip)
   327→			return nil
   328→		}
   329→		podIPs = append(podIPs, podSandbox.Network.Ip)
   330→	}
   331→
   332→	// pick additional ips, if cri reported them
   333→	for _, podIP := range podSandbox.Network.AdditionalIps {
   334→		if nil == netutils.ParseIPSloppy(podIP.Ip) {
   335→			klog.InfoS("Pod Sandbox reported an unparseable additional IP", "pod", klog.KRef(podNamespace, podName), "IP", podIP.Ip)
   336→			return nil
   337→		}
   338→		podIPs = append(podIPs, podIP.Ip)
   339→	}
   340→
   341→	return podIPs
   342→}
   343→
   344→// getPodSandboxID gets the sandbox id by podUID and returns ([]sandboxID, error).
   345→// Param state could be nil in order to get all sandboxes belonging to same pod.
   346→func (m *kubeGenericRuntimeManager) getSandboxIDByPodUID(ctx context.Context, podUID kubetypes.UID, state *runtimeapi.PodSandboxState) ([]string, error) {
   347→	filter := &runtimeapi.PodSandboxFilter{
   348→		LabelSelector: map[string]string{types.KubernetesPodUIDLabel: string(podUID)},
   349→	}
   350→	if state != nil {
   351→		filter.State = &runtimeapi.PodSandboxStateValue{
   352→			State: *state,
   353→		}
   354→	}
   355→	sandboxes, err := m.runtimeService.ListPodSandbox(ctx, filter)
   356→	if err != nil {
   357→		klog.ErrorS(err, "Failed to list sandboxes for pod", "podUID", podUID)
   358→		return nil, err
   359→	}
   360→
   361→	if len(sandboxes) == 0 {
   362→		return nil, nil
   363→	}
   364→
   365→	// Sort with newest first.
   366→	sandboxIDs := make([]string, len(sandboxes))
   367→	sort.Sort(podSandboxByCreated(sandboxes))
   368→	for i, s := range sandboxes {
   369→		sandboxIDs[i] = s.Id
   370→	}
   371→
   372→	return sandboxIDs, nil
   373→}
   374→
   375→// GetPortForward gets the endpoint the runtime will serve the port-forward request from.
   376→func (m *kubeGenericRuntimeManager) GetPortForward(ctx context.Context, podName, podNamespace string, podUID kubetypes.UID, ports []int32) (*url.URL, error) {
   377→	sandboxIDs, err := m.getSandboxIDByPodUID(ctx, podUID, nil)
   378→	if err != nil {
   379→		return nil, fmt.Errorf("failed to find sandboxID for pod %s: %v", format.PodDesc(podName, podNamespace, podUID), err)
   380→	}
   381→	if len(sandboxIDs) == 0 {
   382→		return nil, fmt.Errorf("failed to find sandboxID for pod %s", format.PodDesc(podName, podNamespace, podUID))
   383→	}
   384→	req := &runtimeapi.PortForwardRequest{
   385→		PodSandboxId: sandboxIDs[0],
   386→		Port:         ports,
   387→	}
   388→	resp, err := m.runtimeService.PortForward(ctx, req)
   389→	if err != nil {
   390→		return nil, err
   391→	}
   392→	return url.Parse(resp.Url)
   393→}
   394→

